import{c as t,Q as r,j as i,m as a}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"Arbiter: Detecting Interference in LLM Agent System Prompts — Cross-Vendor Analysis","description":"","frontmatter":{"url":"https://arxiv.org/html/2603.08993v1","date":"2026-05-09T00:00:00.000Z","source":"Arbiter Research Paper / arXiv","tags":["system-prompt-analysis","cross-vendor","failure-modes","architectural-patterns","Model-Harness-Fit"]},"headers":[],"relativePath":"research/ai-articles/scored/2026-05-09-arbiter-system-prompt-interference.md","filePath":"research/ai-articles/scored/2026-05-09-arbiter-system-prompt-interference.md","lastUpdated":1779796674000}'),o={name:"research/ai-articles/scored/2026-05-09-arbiter-system-prompt-interference.md"};function s(l,e,n,d,c,m){return r(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="arbiter-detecting-interference-in-llm-agent-system-prompts-—-cross-vendor-analysis" tabindex="-1">Arbiter: Detecting Interference in LLM Agent System Prompts — Cross-Vendor Analysis <a class="header-anchor" href="#arbiter-detecting-interference-in-llm-agent-system-prompts-—-cross-vendor-analysis" aria-label="Permalink to &quot;Arbiter: Detecting Interference in LLM Agent System Prompts — Cross-Vendor Analysis&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://arxiv.org/html/2603.08993v1" target="_blank" rel="noreferrer">https://arxiv.org/html/2603.08993v1</a><br><strong>歸檔日期</strong>：2026-05-09</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>Arbiter 論文分析三大 agent harness（Claude Code、Codex CLI、Gemini CLI）的系統提示，發現各自特異的結構矛盾。例：Claude Code 的 TodoWrite mandate 與 workflow 禁止直接衝突（4 個 critical 矛盾）。論文產生跨廠商的 107 個獨特發現類別，成本僅 $0.27 USD，驗證了 harness 文本不同的架構選擇導致不同的失敗模態。</p><hr><h2 id="核心主張" tabindex="-1">核心主張 <a class="header-anchor" href="#核心主張" aria-label="Permalink to &quot;核心主張&quot;">​</a></h2><ol><li><p><strong>Harness 架構決定失敗模式類型</strong></p><ul><li><strong>Monolithic</strong>（Claude Code, 1,490 行）：增長型漏洞（subsystem 矛盾累積）</li><li><strong>Flat</strong>（Codex CLI, 298 行）：簡潔但能力受限</li><li><strong>Modular</strong>（Gemini CLI, 245 行）：composition seams 的設計級漏洞</li><li>同一缺陷不會在三種架構上同時出現 → 架構本身決定脆弱模式</li></ul></li><li><p><strong>跨模型互補性而非冗餘</strong></p><ul><li>十個模型針對 116 個發現生成 107 個獨特分類</li><li>Kimi K2.5 的「經濟/資源視角」在 Claude Opus 的分析中完全缺席</li><li>Implication：多模型審查不是浪費，而是發現型號特定的盲點</li></ul></li><li><p><strong>文本層級的不可見性</strong></p><ul><li>Claude Code 的 TodoWrite mandate 隱含在文本中，不可從 frontmatter 自動驗證</li><li>Codex 的 memory mutation 規則分散在 Phase 2 prompt 的 841 行深處</li><li>人類 code review 無法發現這類結構矛盾</li></ul></li><li><p><strong>System Prompt 作為 Wire Format 的一部分</strong></p><ul><li>「System prompt 矛盾」並非 bug 而是 harness 架構選擇的必然產物</li><li>模型被 trained on 這個矛盾的 prompt，對此有適應（或損傷）</li><li>跨 harness 移植 prompt 時會拉出新的矛盾</li></ul></li></ol><hr><h2 id="直接意涵" tabindex="-1">直接意涵 <a class="header-anchor" href="#直接意涵" aria-label="Permalink to &quot;直接意涵&quot;">​</a></h2><h3 id="cc-workspace-可行動性" tabindex="-1">cc-workspace 可行動性 <a class="header-anchor" href="#cc-workspace-可行動性" aria-label="Permalink to &quot;cc-workspace 可行動性&quot;">​</a></h3><ol><li><p><strong>CLAUDE.md 的「自動載入」規則衝突檢測</strong></p><ul><li>cc-workspace CLAUDE.md 已達 ~150 行（monolithic 傾向）</li><li>建議建立「rule conflict audit」工具：scan <code>.claude/rules/</code> for implicit contradictions</li><li>例：「避免 git add -A」vs「git commit 強制 pre-commit-review hook」—有沒有場景兩者衝突？</li></ul></li><li><p><strong>Post-Training Harness Compatibility Matrix</strong></p><ul><li>此論文強調：Harness 文本結構在 model post-training 中被編碼</li><li>Claude 模型被 trained on 「CLAUDE.md monolithic format with specific rule sequences」</li><li>移植至 Codex 時，Codex 被 trained on different rule ordering → behavioral shift</li><li>推薦補充進 <code>.claude/refs/harness-design.md</code> 的新段：「Harness Text Structure Specifies Model Training Distribution」</li></ul></li><li><p><strong>Gemini「History Compression Data Loss」的教訓</strong></p><ul><li>論文發現：Gemini CLI modular harness 設計在 context 壓縮時誤刪用戶偏好</li><li>cc-workspace 的 <code>/compact</code> 命令是否有類似風險？</li><li>建議在 <code>.claude/rules/context-management.md</code> 添加「compact safety checklist」</li></ul></li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>發現 harness 架構與失敗模式的對應；適合作為 audit framework 藍本</td></tr><tr><td>B. 創新性</td><td>8/10</td><td>Cross-vendor system prompt 分析前所未有；107 unique finding 分類新穎</td></tr><tr><td>C. 證據品質</td><td>8/10</td><td>量化（$0.27 成本、10 模型）+ 獨立確認（Google&#39;s Gemini bug report）；但樣本量相對小</td></tr><tr><td>D. 技術深度</td><td>9/10</td><td>深入每個 harness 的文本結構、rule ordering、架構選擇；分析精細</td></tr><tr><td>E. 泛化性</td><td>7/10</td><td>原則（architecture→failure modes）通用；但具體發現 Claude/Codex/Gemini 特化</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.9/10</strong></td><td>8×0.3 + 8×0.2 + 8×0.2 + 9×0.15 + 7×0.15 = 2.4+1.6+1.6+1.35+1.05 = 8.0</td></tr></tbody></table><p><strong>整合決策</strong>：Rule + Reference（補充進 <code>.claude/rules/</code> 的新檔 <code>harness-audit.md</code>；同步更新 <code>.claude/refs/harness-design.md</code>）</p><hr><h2 id="引用關聯" tabindex="-1">引用關聯 <a class="header-anchor" href="#引用關聯" aria-label="Permalink to &quot;引用關聯&quot;">​</a></h2><ul><li>推文 @nicbstme 2026-05-04：System prompt skeleton 與 identity file convention</li><li><code>.claude/rules/core.md</code>：Current harness rule structure</li><li><code>.claude/refs/harness-design.md</code>：Architecture patterns</li></ul>',19)])])}const u=t(o,[["render",s]]);export{h as __pageData,u as default};
